363	/* when the value has lots of elements, we want to handle it later and not as
364	 * part of the main dictionary scan. this is needed in order to prevent latency
365	 * spikes when handling large items */
366	static void defragLater(robj *obj) {
367	    if (!defrag_later) {
368	        defrag_later = listCreate();
369	        listSetFreeMethod(defrag_later, sdsfreeVoid);
370	        defrag_later_cursor = 0;
371	    }
372	    sds key = sdsdup(objectGetKey(obj));
373	    listAddNodeTail(defrag_later, key);
374	}
