1014	// Called at the end of a complete defrag cycle, or when defrag is terminated
1015	static void endDefragCycle(bool normal_termination) {
1016	    if (normal_termination) {
1017	        // For normal termination, we expect...
1018	        serverAssert(!defrag.current_stage);
1019	        serverAssert(listLength(defrag.remaining_stages) == 0);
1020	    } else {
1021	        // Defrag is being terminated abnormally
1022	        aeDeleteTimeEvent(server.el, defrag.timeproc_id);
1023	
1024	        if (defrag.current_stage) {
1025	            zfree(defrag.current_stage);
1026	            defrag.current_stage = NULL;
1027	        }
1028	        listSetFreeMethod(defrag.remaining_stages, zfree);
1029	    }
1030	    defrag.timeproc_id = AE_DELETED_EVENT_ID;
1031	
1032	    listRelease(defrag.remaining_stages);
1033	    defrag.remaining_stages = NULL;
1034	
1035	    /* For a normal termination, this list is usually empty, but it might contain elements
1036	     *  if a stage was aborted due to a flushall or some other DB swap. */
1037	    if (defrag_later) {
1038	        listRelease(defrag_later);
1039	        defrag_later = NULL;
1040	    }
1041	    defrag_later_cursor = 0;
1042	
1043	    size_t frag_bytes;
1044	    float frag_pct = getAllocatorFragmentation(&frag_bytes);
1045	    serverLog(LL_VERBOSE, "Active defrag done in %dms, reallocated=%d, frag=%.0f%%, frag_bytes=%zu",
1046	              (int)elapsedMs(defrag.start_cycle), (int)(server.stat_active_defrag_hits - defrag.start_defrag_hits),
1047	              frag_pct, frag_bytes);
1048	
1049	    server.stat_total_active_defrag_time += elapsedUs(server.stat_last_active_defrag_time);
1050	    server.stat_last_active_defrag_time = 0;
1051	    server.active_defrag_cpu_percent = 0;
1052	
1053	    /* Immediately check to see if we should start another defrag cycle. */
1054	    monitorActiveDefrag();
1055	}
