1058	/* Must be called at the start of the timeProc as it measures the delay from the end of the previous
1059	 * timeProc invocation when performing the computation. */
1060	static int computeDefragCycleUs(void) {
1061	    long dutyCycleUs;
1062	
1063	    int targetCpuPercent = server.active_defrag_cpu_percent;
1064	    serverAssert(targetCpuPercent > 0 && targetCpuPercent < 100);
1065	
1066	    static int prevCpuPercent = 0; // STATIC - this persists
1067	    if (targetCpuPercent != prevCpuPercent) {
1068	        /* If the targetCpuPercent changes, the value might be different from when the last wait
1069	         *  time was computed.  In this case, don't consider wait time.  (This is really only an
1070	         *  issue in crazy tests that dramatically increase CPU while defrag is running.) */
1071	        defrag.timeproc_end_time = 0;
1072	        prevCpuPercent = targetCpuPercent;
1073	    }
1074	
1075	    // Given when the last duty cycle ended, compute time needed to achieve the desired percentage.
1076	    if (defrag.timeproc_end_time == 0) {
1077	        // Either the first call to the timeProc, or we were paused for some reason.
1078	        defrag.timeproc_overage_us = 0;
1079	        dutyCycleUs = server.active_defrag_cycle_us;
1080	    } else {
1081	        long waitedUs = getMonotonicUs() - defrag.timeproc_end_time;
1082	        /* Given the elapsed wait time between calls, compute the necessary duty time needed to
1083	         *  achieve the desired CPU percentage.
1084	         *  With:  D = duty time, W = wait time, P = percent
1085	         *  Solve:    D          P
1086	         *          -----   =  -----
1087	         *          D + W       100
1088	         *  Solving for D:
1089	         *     D = P * W / (100 - P)
1090	         *
1091	         * Note that dutyCycleUs addresses starvation.  If the wait time was long, we will compensate
1092	         *  with a proportionately long duty-cycle.  This won't significantly affect perceived
1093	         *  latency, because clients are already being impacted by the long cycle time which caused
1094	         *  the starvation of the timer. */
1095	        dutyCycleUs = targetCpuPercent * waitedUs / (100 - targetCpuPercent);
1096	
1097	        // Also adjust for any accumulated overage.
1098	        dutyCycleUs -= defrag.timeproc_overage_us;
1099	        defrag.timeproc_overage_us = 0;
1100	
1101	        if (dutyCycleUs < server.active_defrag_cycle_us) {
1102	            /* We never reduce our cycle time, that would increase overhead.  Instead, we track this
1103	             *  as part of the overage, and increase wait time between cycles. */
1104	            defrag.timeproc_overage_us = server.active_defrag_cycle_us - dutyCycleUs;
1105	            dutyCycleUs = server.active_defrag_cycle_us;
1106	        }
1107	    }
1108	    return dutyCycleUs;
1109	}
1110	
1111	
1112	/* Must be called at the end of the timeProc as it records the timeproc_end_time for use in the next
1113	 * computeDefragCycleUs computation. */
1114	static int computeDelayMs(monotime intendedEndtime) {
1115	    defrag.timeproc_end_time = getMonotonicUs();
1116	    long overage = defrag.timeproc_end_time - intendedEndtime;
1117	    defrag.timeproc_overage_us += overage; // track over/under desired CPU
1118	    /* Allow negative overage (underage) to count against existing overage, but don't allow
1119	     * underage (from short stages) to be accumulated.  */
1120	    if (defrag.timeproc_overage_us < 0) defrag.timeproc_overage_us = 0;
1121	
1122	    int targetCpuPercent = server.active_defrag_cpu_percent;
1123	    serverAssert(targetCpuPercent > 0 && targetCpuPercent < 100);
1124	
1125	    // Given the desired duty cycle, what inter-cycle delay do we need to achieve that?
1126	    // We want to achieve a specific CPU percent.  To do that, we can't use a skewed computation.
1127	    // Example, if we run for 1ms and delay 10ms, that's NOT 10%, because the total cycle time is 11ms.
1128	    // Instead, if we rum for 1ms, our total time should be 10ms.  So the delay is only 9ms.
1129	    long totalCycleTimeUs = server.active_defrag_cycle_us * 100 / targetCpuPercent;
1130	    long delayUs = totalCycleTimeUs - server.active_defrag_cycle_us;
1131	    // Only increase delay by the fraction of the overage that would be non-duty-cycle
1132	    delayUs += defrag.timeproc_overage_us * (100 - targetCpuPercent) / 100;
1133	    if (delayUs < 0) delayUs = 0;
1134	    long delayMs = delayUs / 1000; // round down
1135	    return delayMs;
1136	}
1137	
1138	
1139	/* An independent time proc for defrag.  While defrag is running, this is called much more often
1140	 *  than the server cron.  Frequent short calls provides low latency impact. */
1141	static long long activeDefragTimeProc(struct aeEventLoop *eventLoop, long long id, void *clientData) {
1142	    UNUSED(eventLoop);
1143	    UNUSED(id);
1144	    UNUSED(clientData);
1145	
1146	    // This timer shouldn't be registered unless there's work to do.
1147	    serverAssert(defrag.current_stage || listLength(defrag.remaining_stages) > 0);
1148	
1149	    if (!server.active_defrag_enabled) {
1150	        // Defrag has been disabled while running
1151	        endDefragCycle(false);
1152	        return AE_NOMORE;
1153	    }
1154	
1155	    if (hasActiveChildProcess()) {
1156	        // If there's a child process, pause the defrag, polling until the child completes.
1157	        defrag.timeproc_end_time = 0; // prevent starvation recovery
1158	        return 100;
1159	    }
1160	
1161	    monotime starttime = getMonotonicUs();
1162	    int dutyCycleUs = computeDefragCycleUs();
1163	    monotime endtime = starttime + dutyCycleUs;
1164	    bool haveMoreWork = true;
1165	
1166	    mstime_t latency;
1167	    latencyStartMonitor(latency);
1168	
1169	    do {
1170	        if (!defrag.current_stage) {
1171	            defrag.current_stage = listNodeValue(listFirst(defrag.remaining_stages));
1172	            listDelNode(defrag.remaining_stages, listFirst(defrag.remaining_stages));
1173	            // Initialize the stage with endtime==0
1174	            doneStatus status = defrag.current_stage->stage_fn(0, defrag.current_stage->target, defrag.current_stage->privdata);
1175	            serverAssert(status == DEFRAG_NOT_DONE); // Initialization should always return DEFRAG_NOT_DONE
1176	        }
1177	
1178	        doneStatus status = defrag.current_stage->stage_fn(endtime, defrag.current_stage->target, defrag.current_stage->privdata);
1179	        if (status == DEFRAG_DONE) {
1180	            zfree(defrag.current_stage);
1181	            defrag.current_stage = NULL;
1182	        }
1183	
1184	        haveMoreWork = (defrag.current_stage || listLength(defrag.remaining_stages) > 0);
1185	        /* If we've completed a stage early, and still have a standard time allotment remaining,
1186	         * we'll start another stage.  This can happen when defrag is running infrequently, and
1187	         * starvation protection has increased the duty-cycle. */
1188	    } while (haveMoreWork && getMonotonicUs() <= endtime - server.active_defrag_cycle_us);
1189	
1190	    latencyEndMonitor(latency);
1191	    latencyAddSampleIfNeeded("active-defrag-cycle", latency);
1192	    latencyTraceIfNeeded(db, active_defrag_cycle, latency);
1193	    if (haveMoreWork) {
1194	        return computeDelayMs(endtime);
1195	    } else {
1196	        endDefragCycle(true);
1197	        return AE_NOMORE; // Ends the timer proc
1198	    }
1199	}
1200	
1201	
1202	/* During long running scripts, or while loading, there is a periodic function for handling other
1203	 * actions.  This interface allows defrag to continue running, avoiding a single long defrag step
1204	 * after the long operation completes. */
1205	void defragWhileBlocked(void) {
1206	    // This is called infrequently, while timers are not active.  We might need to start defrag.
1207	    if (!defragIsRunning()) monitorActiveDefrag();
1208	
1209	    if (!defragIsRunning()) return;
1210	
1211	    // Save off the timeproc_id.  If we have a normal termination, it will be cleared.
1212	    long long timeproc_id = defrag.timeproc_id;
1213	
1214	    // Simulate a single call of the timer proc
1215	    long long reschedule_delay = activeDefragTimeProc(NULL, 0, NULL);
1216	    if (reschedule_delay == AE_NOMORE) {
1217	        // If it's done, deregister the timer
1218	        aeDeleteTimeEvent(server.el, timeproc_id);
1219	    }
1220	    /* Otherwise, just ignore the reschedule_delay, the timer will pop the next time that the
1221	     * event loop can process timers again. */
1222	}
1223	
1224	
1225	static void beginDefragCycle(void) {
1226	    serverAssert(!defragIsRunning());
1227	
1228	    serverAssert(defrag.remaining_stages == NULL);
1229	    defrag.remaining_stages = listCreate();
1230	
1231	    for (int dbid = 0; dbid < server.dbnum; dbid++) {
1232	        /* Skip the non-existent dbs but not empty dbs since hashtableDefragTables
1233	         * still defrags the internal allocations of the hashtables structs if they
1234	         * exist. */
1235	        if (server.db[dbid] == NULL) continue;
1236	
1237	        addDefragStage(defragStageDbKeys, (void *)(uintptr_t)dbid, NULL);
1238	        addDefragStage(defragStageExpiresKvstore, (void *)(uintptr_t)dbid, NULL);
1239	        addDefragStage(defragStageKeysWithvolaItemsKvstore, (void *)(uintptr_t)dbid, NULL);
1240	    }
1241	
1242	    static getClientChannelsFnWrapper getClientPubSubChannelsFn = {getClientPubSubChannels};
1243	    static getClientChannelsFnWrapper getClientPubSubShardChannelsFn = {getClientPubSubShardChannels};
1244	    addDefragStage(defragStagePubsubKvstore, server.pubsub_channels, &getClientPubSubChannelsFn);
1245	    addDefragStage(defragStagePubsubKvstore, server.pubsubshard_channels, &getClientPubSubShardChannelsFn);
1246	
1247	    addDefragStage(defragLuaScripts, NULL, NULL);
1248	    addDefragStage(defragModuleGlobals, NULL, NULL);
1249	
1250	    defrag.current_stage = NULL;
1251	    defrag.start_cycle = getMonotonicUs();
1252	    defrag.start_defrag_hits = server.stat_active_defrag_hits;
1253	    defrag.timeproc_end_time = 0;
1254	    defrag.timeproc_overage_us = 0;
1255	    defrag.timeproc_id = aeCreateTimeEvent(server.el, 0, activeDefragTimeProc, NULL, NULL);
1256	
1257	    elapsedStart(&server.stat_last_active_defrag_time);
1258	}
1259	
1260	
1261	#define INTERPOLATE(x, x1, x2, y1, y2) ((y1) + ((x) - (x1)) * ((y2) - (y1)) / ((x2) - (x1)))
1262	#define LIMIT(y, min, max) ((y) < (min) ? min : ((y) > (max) ? max : (y)))
1263	
1264	/* decide if defrag is needed, and at what CPU effort to invest in it */
1265	static void updateDefragCpuPercent(void) {
1266	    size_t frag_bytes;
1267	    float frag_pct = getAllocatorFragmentation(&frag_bytes);
1268	    if (server.active_defrag_cpu_percent == 0) {
1269	        if (frag_pct < server.active_defrag_threshold_lower ||
1270	            frag_bytes < server.active_defrag_ignore_bytes) return;
1271	    }
1272	
1273	    /* Calculate the adaptive aggressiveness of the defrag based on the current
1274	     * fragmentation and configurations. */
1275	    int cpu_pct = INTERPOLATE(frag_pct, server.active_defrag_threshold_lower, server.active_defrag_threshold_upper,
1276	                              server.active_defrag_cpu_min, server.active_defrag_cpu_max);
1277	    cpu_pct = LIMIT(cpu_pct, server.active_defrag_cpu_min, server.active_defrag_cpu_max);
1278	
1279	    /* Normally we allow increasing the aggressiveness during a scan, but don't
1280	     * reduce it, since we should not lower the aggressiveness when fragmentation
1281	     * drops. But when a configuration is made, we should reconsider it. */
1282	    if (cpu_pct > server.active_defrag_cpu_percent || server.active_defrag_configuration_changed) {
1283	        server.active_defrag_configuration_changed = 0;
1284	        if (defragIsRunning()) {
1285	            serverLog(LL_VERBOSE, "Changing active defrag CPU, frag=%.0f%%, frag_bytes=%zu, cpu=%d%%",
1286	                      frag_pct, frag_bytes, cpu_pct);
1287	        } else {
1288	            serverLog(LL_VERBOSE, "Starting active defrag, frag=%.0f%%, frag_bytes=%zu, cpu=%d%%",
1289	                      frag_pct, frag_bytes, cpu_pct);
1290	        }
1291	        server.active_defrag_cpu_percent = cpu_pct;
1292	    }
1293	}
1294	
1295	
1296	void monitorActiveDefrag(void) {
1297	    if (!server.active_defrag_enabled) return;
1298	
1299	    /* Defrag gets paused while a child process is active.  So there's no point in starting a new
1300	     *  cycle or adjusting the CPU percentage for an existing cycle. */
1301	    if (hasActiveChildProcess()) return;
1302	
1303	    updateDefragCpuPercent();
1304	
1305	    if (server.active_defrag_cpu_percent > 0 && !defragIsRunning()) beginDefragCycle();
1306	}
1307	
1308	#else /* HAVE_DEFRAG */
1309	
1310	void monitorActiveDefrag(void) {
1311	    /* Not implemented yet. */
1312	}
1313	
1314	void *activeDefragAlloc(void *ptr) {
1315	    UNUSED(ptr);
1316	    return NULL;
1317	}
1318	
1319	robj *activeDefragStringOb(robj *ob) {
1320	    UNUSED(ob);
1321	    return NULL;
1322	}
1323	
1324	void defragWhileBlocked(void) {
1325	}
1326	
1327	sds activeDefragSds(sds sdsptr) {
1328	    return sdsptr;
1329	}
1330	
1331	#endif
1332	

